python3 -c "
import json, os, sys, time, urllib.request, uuid
PENDING = os.path.expanduser('~/.engram/pending.jsonl')
def send(url, key, content, delayed=False):
    args = {'content': content, 'scope': 'general', 'confidence': 0.8, 'fact_type': 'observation', 'invite_key': key}
    if delayed: args['delayed'] = True
    body = json.dumps({'jsonrpc': '2.0', 'id': str(uuid.uuid4()), 'method': 'tools/call', 'params': {'name': 'engram_commit', 'arguments': args}}).encode()
    req = urllib.request.Request(url.rstrip('/') + '/mcp', data=body, headers={'Authorization': 'Bearer ' + key, 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream'}, method='POST')
    urllib.request.urlopen(req, timeout=5)
def buffer(content):
    try:
        os.makedirs(os.path.dirname(PENDING), exist_ok=True)
        with open(PENDING, 'a') as f: f.write(json.dumps({'content': content, 'ts': time.time()}) + '\n')
    except Exception: pass
def drain(url, key):
    if not os.path.exists(PENDING): return
    try:
        with open(PENDING) as f: lines = f.readlines()
        if not lines: return
        remaining = []
        for line in lines:
            try: send(url, key, json.loads(line.strip())['content'], delayed=True)
            except Exception: remaining.append(line)
        with open(PENDING, 'w') as f: f.writelines(remaining)
    except Exception: pass
try:
    prompt = os.environ.get('USER_PROMPT', '').strip()
    if not prompt: sys.exit(0)
    server_url = 'https://www.engram-memory.com'
    invite_key = ''
    for f in [os.path.expanduser('~/.engram/credentials'), os.path.join(os.getcwd(), '.engram.env')]:
        if os.path.exists(f):
            for line in open(f).read().splitlines():
                if line.startswith('ENGRAM_SERVER_URL='): server_url = line[18:].strip()
                elif line.startswith('ENGRAM_INVITE_KEY='): invite_key = line[18:].strip()
    if not invite_key: sys.exit(0)
    try:
        send(server_url, invite_key, prompt)
        drain(server_url, invite_key)
    except Exception as exc:
        buffer(prompt)
        print('engram: commit buffered locally (' + str(exc) + ')', file=sys.stderr)
except Exception as exc:
    print('engram: hook error (' + str(exc) + ')', file=sys.stderr)
"
